467	          }
468	        });
469	      }
470	    }
471	    scrollToBottom();
472	  }
473	
474	  function renderDiff(container, diff) {
475	    var el = document.createElement("div");
476	    el.className = "chat-diff";
477	    var header = document.createElement("div");
478	    header.className = "chat-diff-header";
479	    header.textContent = diff.path || "file";
480	    el.appendChild(header);
481	
482	    var pre = document.createElement("pre");
483	    pre.className = "chat-diff-content";
484	    // Simple diff display: show newText (the result)
485	    pre.textContent = diff.newText || "";
486	    el.appendChild(pre);
487	    container.appendChild(el);
488	  }
489	
490	  // --- Rendering: Plan ---
491	
492	  function renderPlan(tabData, entries) {
493	    // Remove any existing plan
494	    var existing = tabData.container.querySelector(".chat-plan");
495	    if (existing) existing.parentNode.removeChild(existing);
496	
497	    if (!entries.length) return;
498	
499	    var el = document.createElement("div");
500	    el.className = "chat-plan";
501	    el.innerHTML = "<div class='chat-plan-title'>Plan</div>";
502	    var list = document.createElement("ul");
503	    entries.forEach(function (entry) {
504	      var li = document.createElement("li");
505	      var statusIcon = entry.status === "completed" ? "&#10003;" : entry.status === "failed" ? "&#10007;" : "&#9744;";
506	      li.innerHTML = '<span class="chat-plan-icon">' + statusIcon + '</span> ' + escapeHtml(entry.content || "");
507	      li.className = "chat-plan-entry " + (entry.status || "pending");
508	      list.appendChild(li);
509	    });
510	    el.appendChild(list);
511	    tabData.container.appendChild(el);
512	    scrollToBottom();
513	  }
514	
515	  // --- Rendering: Usage ---
516	
517	  function renderUsage(msg) {
518	    if (!$chatCost) return;
519	    var parts = [];
520	
521	    if (msg.cost && msg.cost.amount != null) {
522	      parts.push("$" + msg.cost.amount.toFixed(4));
523	    }
524	
525	    if (msg.used != null && msg.size != null && msg.size > 0) {
526	      var usedK = Math.round(msg.used / 1000);
527	      var sizeK = Math.round(msg.size / 1000);
528	      var pct = Math.round((msg.used / msg.size) * 100);
529	      parts.push(usedK + "K / " + sizeK + "K (" + pct + "%)");
530	    }
531	
532	    if (parts.length > 0) {
533	      $chatCost.textContent = parts.join(" | ");
534	      $chatCost.classList.remove("hidden", "context-warn", "context-critical");
535	      if (msg.used != null && msg.size != null && msg.size > 0) {
536	        var pct = (msg.used / msg.size) * 100;
537	        if (pct >= 90) {
538	          $chatCost.classList.add("context-critical");
539	        } else if (pct >= 75) {
540	          $chatCost.classList.add("context-warn");
541	        }
542	      }
543	    }
544	  }
545	
546	  // --- Turn Navigation Sidebar ---
547	
548	  var $turnSidebar = document.getElementById("chat-turn-sidebar");
549	
550	  function renderTurnSidebar(tabData) {
551	    if (!$turnSidebar) return;
552	    var list = $turnSidebar.querySelector(".turn-list");
553	    if (list) list.innerHTML = "";
554	    var turns = tabData.userTurns;
555	    if (turns.length === 0) {
556	      $turnSidebar.classList.add("hidden");
557	      return;
558	    }
559	
560	    $turnSidebar.classList.remove("hidden");
561	    if (!list) return;
562	
563	    turns.forEach(function (turn) {
564	      var item = document.createElement("div");
565	      item.className = "turn-item" + (turn.index === tabData.activeTurnIndex ? " active" : "");
566	      item.setAttribute("data-turn-index", turn.index);
567	
568	      var label = document.createElement("span");
569	      label.className = "turn-label";
570	      label.textContent = (turn.index + 1);
571	
572	      var preview = document.createElement("span");
573	      preview.className = "turn-preview";
574	      var previewText = turn.text.length > 60 ? turn.text.substring(0, 60) + "..." : turn.text;
575	      preview.textContent = previewText;
576	
577	      item.appendChild(label);
578	      item.appendChild(preview);
579	      item.addEventListener("click", function () {
580	        jumpToTurn(tabData, turn.index);
581	      });
582	      list.appendChild(item);
583	    });
584	
585	    // Update counter
586	    var counter = $turnSidebar.querySelector(".turn-counter");
587	    if (counter) {
588	      var current = tabData.activeTurnIndex >= 0 ? (tabData.activeTurnIndex + 1) : "-";
589	      counter.textContent = current + " / " + turns.length;
590	    }
591	  }
592	
593	  function jumpToTurn(tabData, turnIndex) {
594	    var turns = tabData.userTurns;
595	    if (turnIndex < 0 || turnIndex >= turns.length) return;
596	
597	    tabData.activeTurnIndex = turnIndex;
598	    var el = turns[turnIndex].element;
599	    el.scrollIntoView({ behavior: "smooth", block: "center" });
600	
601	    // Brief highlight flash
602	    el.classList.add("turn-highlight");
603	    setTimeout(function () { el.classList.remove("turn-highlight"); }, 1500);
604	
605	    renderTurnSidebar(tabData);
606	  }
607	
608	  function jumpToPreviousTurn(tabData) {
609	    if (!tabData || tabData.userTurns.length === 0) return;
610	    var next = tabData.activeTurnIndex <= 0 ? 0 : tabData.activeTurnIndex - 1;
611	    jumpToTurn(tabData, next);
612	  }
613	
614	  function jumpToNextTurn(tabData) {
615	    if (!tabData || tabData.userTurns.length === 0) return;
616	    var max = tabData.userTurns.length - 1;
617	    var next = tabData.activeTurnIndex >= max ? max : tabData.activeTurnIndex + 1;
618	    jumpToTurn(tabData, next);
619	  }
620	
621	  // Toggle sidebar visibility
622	  function toggleTurnSidebar() {
623	    if (!$turnSidebar) return;
624	    $turnSidebar.classList.toggle("collapsed");
625	  }
626	
627	  // --- Tool Collapsing ---
628	
629	  function collapseCompletedTools(tabData) {
630	    var container = tabData.container;
631	    var children = Array.from(container.children);
632	    var i = 0;
633	
634	    while (i < children.length) {
635	      // Find runs of consecutive completed tool cards
636	      if (isCompletedToolCard(children[i])) {
637	        var runStart = i;
638	        while (i < children.length && isCompletedToolCard(children[i])) {
639	          i++;
640	        }
641	        var runLength = i - runStart;
642	        if (runLength >= 3) {
643	          var details = container.ownerDocument.createElement("details");
644	          details.className = "chat-tool-group";
645	          var summary = container.ownerDocument.createElement("summary");
646	          summary.textContent = runLength + " tool calls completed";
647	          details.appendChild(summary);
648	
649	          // Insert the details element before the first card in the run
650	          container.insertBefore(details, children[runStart]);
651	          for (var j = runStart; j < runStart + runLength; j++) {
652	            details.appendChild(children[j]);
653	          }
654	        }
655	      } else {
656	        i++;
657	      }
658	    }
659	  }
660	
661	  function isCompletedToolCard(el) {
662	    if (!el || !el.classList || !el.classList.contains("chat-tool-card")) return false;
663	    var statusEl = el.querySelector(".chat-tool-status");
664	    return statusEl && statusEl.classList.contains("completed");
665	  }
666	
667	  // --- Rendering: System / Info / Auth ---
668	
669	  function appendSystemMessage(tabData, text) {
670	    var el = document.createElement("div");
671	    el.className = "chat-system-msg";
672	    el.textContent = text;
673	    tabData.container.appendChild(el);
674	    scrollToBottom();
675	  }
676	
677	  function appendInfoBanner(tabData, text) {
678	    var el = document.createElement("div");
679	    el.className = "chat-info-banner";
680	    el.textContent = text;
681	    tabData.container.appendChild(el);
682	    scrollToBottom();
683	  }
684	
685	  function appendSessionTerminated(tabData) {
686	    var el = document.createElement("div");
687	    el.className = "chat-system-msg chat-terminated";
688	    el.textContent = "Session ended — send a message to resume";
689	    tabData.container.appendChild(el);
690	    scrollToBottom();
691	  }
692	
693	  function appendAuthBanner(tabData, msg) {
694	    var el = document.createElement("div");
695	    el.className = "chat-auth-banner";
696	    el.innerHTML =
697	      '<div class="chat-auth-text">' + escapeHtml(msg.message || "Authentication required") + "</div>" +
698	      '<button class="chat-auth-retry">Retry</button>';
699	    el.querySelector(".chat-auth-retry").addEventListener("click", function () {
700	      if (tabData.ws && tabData.ws.readyState === WebSocket.OPEN) {
701	        tabData.ws.send(JSON.stringify({ type: "retry" }));
702	        el.parentNode.removeChild(el);
703	      }
704	    });
705	    tabData.container.appendChild(el);
706	    scrollToBottom();
707	  }
708	
709	  // --- Input Handling ---
710	
711	  function sendUserMessage() {
712	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
713	    var tab = chatTabs[activeChatTabId];
714	
715	    var text = $chatInput.value.trim();
716	    var images = tab.pendingImages.slice();
717	    if (!text && !images.length) return;
718	    $chatInput.value = "";
719	    $chatInput.style.height = "auto";
720	
721	    appendUserBubble(tab, text, images);
722	    tab.pendingImages = [];
723	    renderImagePreview();
724	    updateInputPlaceholder();
725	
726	    var queuedMsg = { type: "user_message", text: text };
727	    if (images.length) {
728	      queuedMsg.images = images.map(function (img) {
729	        return { data: img.data, mimeType: img.mimeType };
730	      });
731	    }
732	
733	    if (tab.streaming) {
734	      if (!tab.messageQueue) tab.messageQueue = [];
735	      tab.messageQueue.push(queuedMsg);
736	      updateInputState();
737	      return;
738	    }
739	
740	    sendToAgent(tab, queuedMsg);
741	  }
742	
743	  function sendToAgent(tab, msg) {
744	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
745	      tab.ws.send(JSON.stringify(msg));
746	      tab.streaming = true;
747	      updateInputState();
748	    }
749	  }
750	
751	  function flushMessageQueue(tab) {
752	    if (!tab.messageQueue || tab.messageQueue.length === 0) return;
753	    var next = tab.messageQueue.shift();
754	    sendToAgent(tab, next);
755	  }
756	
757	  function cancelAgent() {
758	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
759	    var tab = chatTabs[activeChatTabId];
760	    if (!tab.streaming) return;
761	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
762	      tab.ws.send(JSON.stringify({ type: "cancel" }));
763	    }
764	    tab.messageQueue = [];
765	    tab.streaming = false;
766	    appendSystemMessage(tab, "Cancelled by user");
767	    finalizeAssistantMessage(tab);
768	    updateInputState();
769	  }
770	
771	  function updateInputState() {
772	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
773	    var streaming = tab && tab.streaming;
774	    var queued = tab && tab.messageQueue && tab.messageQueue.length > 0;
775	    $chatInput.disabled = false;
776	    // Show stop button during streaming, send button otherwise
777	    if (streaming) {
778	      $chatSend.classList.add("hidden");
779	      $chatStop.classList.remove("hidden");
780	    } else {
781	      $chatSend.classList.remove("hidden");
782	      $chatStop.classList.add("hidden");
783	    }
784	    if (streaming && queued) {
785	      $chatInput.placeholder = queued + " queued...";
786	    } else if (streaming) {
787	      $chatInput.placeholder = "Agent working... Esc to stop";
788	    } else if (tab && tab.terminated) {
789	      $chatInput.placeholder = "Send a message to resume session...";
790	    } else {
791	      $chatInput.placeholder = "Send a message...";
792	    }
793	  }
794	
795	  // Auto-grow textarea
796	  $chatInput.addEventListener("input", function () {
797	    this.style.height = "auto";
798	    this.style.height = Math.min(this.scrollHeight, 150) + "px";
799	  });
800	
801	  // Enter to send, Shift+Enter for newline, Esc to stop
802	  $chatInput.addEventListener("keydown", function (e) {
803	    if (e.key === "Enter" && !e.shiftKey) {
804	      e.preventDefault();
805	      sendUserMessage();
806	    } else if (e.key === "Escape") {
807	      var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
808	      if (tab && tab.streaming) {
809	        e.preventDefault();
810	        cancelAgent();
811	      }
812	    }
813	  });
814	
815	  $chatStop.addEventListener("click", cancelAgent);
816	
817	  $chatSend.addEventListener("click", sendUserMessage);
818	
819	  // --- Image Paste ---
820	
821	  $chatInput.addEventListener("paste", function (e) {
822	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
823	    if (!tab || tab.streaming) return;
824	
825	    var items = e.clipboardData && e.clipboardData.items;
826	    if (!items) return;
827	
828	    for (var i = 0; i < items.length; i++) {
829	      if (items[i].type.indexOf("image/") === 0) {
830	        e.preventDefault();
831	        var file = items[i].getAsFile();
832	        if (!file) continue;
833	        readImageFile(tab, file);
834	      }
835	    }
836	  });
837	
838	  function readImageFile(tab, file) {
839	    var reader = new FileReader();
840	    reader.onload = function () {
841	      // result is "data:<mimeType>;base64,<data>"
842	      var parts = reader.result.split(",");
843	      var mimeType = file.type || "image/png";
844	      var data = parts[1];
845	      tab.pendingImages.push({ data: data, mimeType: mimeType });
846	      renderImagePreview();
847	      updateInputPlaceholder();
848	    };
849	    reader.readAsDataURL(file);
850	  }
851	
852	  function updateInputPlaceholder() {
853	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
854	    if (!tab || tab.streaming || tab.terminated) return;
855	    var n = tab.pendingImages.length;
856	    if (n > 0) {
857	      $chatInput.placeholder = n + " image" + (n > 1 ? "s" : "") + " attached — add text or press Enter to send";
858	    } else {
859	      $chatInput.placeholder = "Send a message...";
860	    }
861	  }
862	
863	  function renderImagePreview() {
864	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
865	    $imagePreview.innerHTML = "";
866	    if (!tab || !tab.pendingImages.length) {
867	      $imagePreview.classList.remove("active");
868	      return;
869	    }
870	    $imagePreview.classList.add("active");
871	    tab.pendingImages.forEach(function (img, idx) {
872	      var thumb = document.createElement("div");
873	      thumb.className = "image-preview-thumb";
874	      var imgEl = document.createElement("img");
875	      imgEl.src = "data:" + img.mimeType + ";base64," + img.data;
876	      thumb.appendChild(imgEl);
877	      var removeBtn = document.createElement("button");
878	      removeBtn.className = "image-preview-remove";
879	      removeBtn.textContent = "\u00d7";
880	      removeBtn.setAttribute("data-idx", idx);
881	      removeBtn.addEventListener("click", function () {
882	        tab.pendingImages.splice(idx, 1);
883	        renderImagePreview();
884	        updateInputPlaceholder();
885	      });
886	      thumb.appendChild(removeBtn);
887	      $imagePreview.appendChild(thumb);
888	    });
889	  }
890	
891	
892	  // Turn navigation keyboard shortcuts (Ctrl+Up/Down)
893	  document.addEventListener("keydown", function (e) {
894	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
895	    var tab = chatTabs[activeChatTabId];
896	    if (!$chatPanel || $chatPanel.classList.contains("hidden")) return;
897	
898	    if (e.ctrlKey && e.key === "ArrowUp") {
899	      e.preventDefault();
900	      jumpToPreviousTurn(tab);
901	    } else if (e.ctrlKey && e.key === "ArrowDown") {
902	      e.preventDefault();
903	      jumpToNextTurn(tab);
904	    } else if (e.ctrlKey && e.key === "t") {
905	      e.preventDefault();
906	      toggleTurnSidebar();
907	    }
908	  });
909	
910	  $chatClose.addEventListener("click", function () {
911	    // Close all tabs
912	    Object.keys(chatTabs).forEach(function (tabId) {
913	      var tab = chatTabs[tabId];
914	      if (tab.ws && tab.ws.readyState === WebSocket.OPEN) tab.ws.close();
915	      if (tab.container && tab.container.parentNode) tab.container.parentNode.removeChild(tab.container);
916	    });
917	    chatTabs = {};
918	    activeChatTabId = null;
919	    $chatPanel.classList.add("hidden");
920	    if ($turnSidebar) $turnSidebar.classList.add("hidden");
921	    document.body.classList.remove("chat-open");
922	    renderChatTabs();
923	  });
924	
925	
926	  // --- Public API (called from app.js) ---
927	
928	  window.AgentChat = {
929	    openChat: function (session) {
930	      // Check for existing tab with same session
931	      var ids = Object.keys(chatTabs);
932	      for (var i = 0; i < ids.length; i++) {
933	        if (chatTabs[ids[i]].sessionId === session.id) {
934	          switchChatTab(ids[i]);
935	          return;
936	        }
937	      }
938	      var agent = session.source || "claude";
939	      var title = session.summary || session.id.substring(0, 8);
940	      createChatTab(title, agent, session.cwd, session.id, session.summary);
941	    },
942	
943	    openNewChat: function (cwd) {
944	      var agent = localStorage.getItem("ak-default-agent") || "claude";
945	      var displayName = cwd.split("/").filter(Boolean).pop() || cwd;
946	      createChatTab("New: " + displayName, agent, cwd, null, null);
947	    },
948	  };
949	
950	  // Exposed for testing — not part of the public API
951	  window._chatInternals = {
952	    handleServerMessage: handleServerMessage,
953	    handleUpdate: handleUpdate,
954	    appendAgentText: appendAgentText,
955	    appendUserBubble: appendUserBubble,
956	    finalizeAssistantMessage: finalizeAssistantMessage,
957	    renderToolCall: renderToolCall,
958	    collapseCompletedTools: collapseCompletedTools,
959	    sendUserMessage: sendUserMessage,
960	    switchChatTab: switchChatTab,
961	    updateInputState: updateInputState,
962	    buildMessagePayload: function (text, images) {
963	      var msg = { type: "user_message", text: text };
964	      if (images && images.length) {
965	        msg.images = images.map(function (img) {
966	          return { data: img.data, mimeType: img.mimeType };
967	        });
968	      }
969	      return msg;
970	    },
971	    getState: function () {
972	      return { chatTabs: chatTabs, activeChatTabId: activeChatTabId };
973	    },
974	    createTabData: function (container) {
975	      return {
976	        id: "test-tab",
977	        ws: null,
978	        sessionId: null,
979	        agent: "claude",
980	        cwd: "/tmp",
981	        container: container,
982	        title: "Test",
983	        streaming: false,
984	        messageQueue: [],
985	        currentTextAccum: "",
986	        currentTextEl: null,
987	        thinkingAccum: "",
988	        thinkingEl: null,
989	        renderScheduled: false,
990	        sessionSummary: null,
991	        userTurns: [],
992	        activeTurnIndex: -1,
993	        pendingImages: [],
994	      };
995	    },
996	  };
997	})();
