1	// ABOUTME: Dashboard client — fetches session data, renders UI, handles interactions.
2	// ABOUTME: Vanilla JS with no build step; polls /api/sessions for updates.
3	
4	(function () {
5	  "use strict";
6	
7	  // --- Theme ---
8	  // Cycles: auto → dark → light → auto. Persisted in localStorage.
9	  // JS manages the .dark class on <html> based on effective theme.
10	
11	  var THEME_CYCLE = ["auto", "dark", "light"];
12	  var THEME_LABELS = { auto: "Auto", dark: "Dark", light: "Light" };
13	  var $themeToggle = document.getElementById("theme-toggle");
14	  var darkMediaQuery = window.matchMedia("(prefers-color-scheme: dark)");
15	
16	  function getStoredTheme() {
17	    return localStorage.getItem("ak-theme") || "auto";
18	  }
19	
20	  function applyTheme(theme) {
21	    var isDark = theme === "dark" || (theme === "auto" && darkMediaQuery.matches);
22	    document.documentElement.classList.toggle("dark", isDark);
23	    $themeToggle.textContent = THEME_LABELS[theme];
24	  }
25	
26	  function cycleTheme() {
27	    var current = getStoredTheme();
28	    var next = THEME_CYCLE[(THEME_CYCLE.indexOf(current) + 1) % THEME_CYCLE.length];
29	    localStorage.setItem("ak-theme", next);
30	    applyTheme(next);
31	  }
32	
33	  // Apply on load
34	  applyTheme(getStoredTheme());
35	
36	  // React to OS theme changes (only matters in auto mode)
37	  darkMediaQuery.addEventListener("change", function () {
38	    if (getStoredTheme() === "auto") applyTheme("auto");
39	  });
40	
41	  $themeToggle.addEventListener("click", cycleTheme);
42	
43	  // --- State ---
44	  let dashboardData = null;
45	  let lastScannedTime = null;
46	  let expandedRepos = new Set(); // repo_root values that are expanded
47	  var timeFilterDays = Infinity; // max days back to show (Infinity = all)
48	
49	  // --- DOM refs ---
50	  const $loading = document.getElementById("loading");
51	  const $repoGroups = document.getElementById("repo-groups");
52	  const $nonRepoGroups = document.getElementById("non-repo-groups");
53	  const $chronoView = document.getElementById("chrono-view");
54	  const $emptyState = document.getElementById("empty-state");
55	  const $lastScan = document.getElementById("last-scan");
56	  const $btnRefresh = document.getElementById("btn-refresh");
57	  const $scanDays = document.getElementById("scan-days");
58	  const $timeSegments = document.getElementById("time-segments");
59	  const $searchOverlay = document.getElementById("search-overlay");
60	  const $searchInput = document.getElementById("search-input");
61	  const $searchResults = document.getElementById("search-results");
62	
63	  // --- Helpers ---
64	
65	  function timeAgo(isoString) {
66	    if (!isoString) return "--";
67	    const diff = Date.now() - new Date(isoString).getTime();
68	    const seconds = Math.floor(diff / 1000);
69	    if (seconds < 60) return seconds + "s ago";
70	    const minutes = Math.floor(seconds / 60);
71	    if (minutes < 60) return minutes + "m ago";
72	    const hours = Math.floor(minutes / 60);
73	    if (hours < 24) return hours + "h ago";
74	    const days = Math.floor(hours / 24);
75	    return days + "d ago";
76	  }
77	
78	  function statusCssClass(status) {
79	    return (status || "").replace(/\s+/g, "-");
80	  }
81	
82	  function isActiveDot(status) {
83	    return ["in progress", "likely in progress", "waiting for input"].includes(status);
84	  }
85	
86	  var INITIAL_VISIBLE = 10;
87	
88	  function escapeHtml(str) {
89	    const div = document.createElement("div");
90	    div.textContent = str || "";
91	    return div.innerHTML;
92	  }
93	
94	  function sessionLabel(session) {
95	    if (session.summary) return session.summary;
96	    if (session.slug) return session.slug;
97	    return session.id.substring(0, 8) + "\u2026";
98	  }
99	
100	  function allSessions() {
101	    if (!dashboardData) return [];
102	    var sessions = [];
103	    (dashboardData.repo_groups || []).forEach(function (g) {
104	      g.sessions.forEach(function (s) {
105	        sessions.push({ session: s, repoName: g.repo_name || "" });
106	      });
107	    });
108	    (dashboardData.non_repo_groups || []).forEach(function (g) {
109	      var name = g.cwd.split("/").filter(Boolean).pop() || g.cwd;
110	      g.sessions.forEach(function (s) {
111	        sessions.push({ session: s, repoName: name });
112	      });
113	    });
114	    return sessions;
115	  }
116	
117	  function fuzzyMatch(text, query) {
118	    var tLower = text.toLowerCase();
119	    var qLower = query.toLowerCase();
120	    var qi = 0;
121	    var indices = [];
122	    for (var ti = 0; ti < tLower.length && qi < qLower.length; ti++) {
123	      if (tLower[ti] === qLower[qi]) {
124	        indices.push(ti);
125	        qi++;
126	      }
127	    }
128	    if (qi < qLower.length) return null;
129	    // Score: prefer consecutive matches and matches at word boundaries
130	    var score = 0;
131	    for (var i = 0; i < indices.length; i++) {
132	      if (i > 0 && indices[i] === indices[i - 1] + 1) score += 10;
133	      if (indices[i] === 0 || text[indices[i] - 1] === " ") score += 5;
134	    }
135	    return { indices: indices, score: score };
136	  }
137	
138	  function highlightMatches(text, indices) {
139	    if (!indices || indices.length === 0) return escapeHtml(text);
140	    var result = "";
141	    var idxSet = new Set(indices);
142	    var inMark = false;
143	    for (var i = 0; i < text.length; i++) {
144	      if (idxSet.has(i) && !inMark) {
145	        result += "<mark>";
146	        inMark = true;
147	      } else if (!idxSet.has(i) && inMark) {
148	        result += "</mark>";
149	        inMark = false;
150	      }
151	      result += escapeHtml(text[i]);
152	    }
153	    if (inMark) result += "</mark>";
154	    return result;
155	  }
156	
157	  function parsePhaseDate(phase) {
158	    // Use start_date (ISO) if available, otherwise parse the period string
159	    if (phase.start_date) {
160	      return new Date(phase.start_date + "T00:00:00").getTime();
161	    }
162	    var period = phase.period || "";
163	    var now = new Date();
164	    if (period === "Today") return new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
165	    if (period === "Yesterday") return new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1).getTime();
166	    // Parse "Mar 17" or "Mar 10-12" (use first date in range)
167	    var months = {Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};
168	    var m = period.match(/^([A-Z][a-z]{2})\s+(\d+)/);
169	    if (m && months[m[1]] !== undefined) {
170	      var year = now.getFullYear();
171	      var d = new Date(year, months[m[1]], parseInt(m[2], 10));
172	      // If the parsed date is in the future, it's from last year
173	      if (d.getTime() > now.getTime() + 86400000) d.setFullYear(year - 1);
174	      return d.getTime();
175	    }
176	    return 0; // can't parse — don't filter
177	  }
178	
179	  function filterSessionByTime(session) {
180	    if (timeFilterDays === Infinity) return true;
181	    if (!session.last_active) return false;
182	    var cutoff = Date.now() - timeFilterDays * 24 * 60 * 60 * 1000;
183	    return new Date(session.last_active).getTime() >= cutoff;
184	  }
185	
186	  function filterGroupSessions(group) {
187	    return group.sessions.filter(filterSessionByTime);
188	  }
189	
190	  // --- Rendering ---
191	
192	  function isSessionFresh(session) {
193	    if (!session.last_active) return false;
194	    var hourAgo = Date.now() - 60 * 60 * 1000;
195	    return new Date(session.last_active).getTime() >= hourAgo;
196	  }
197	
198	  function renderSessionRow(session) {
199	    const cssCls = statusCssClass(session.status);
200	    const row = document.createElement("div");
201	    row.className = "session-row" + (isSessionFresh(session) ? " session-fresh" : "");
202	    row.innerHTML =
203	      '<div class="status-dot ' + cssCls + '"></div>' +
204	      '<div class="session-summary">' + escapeHtml(sessionLabel(session)) + "</div>" +
205	      '<span class="status-label ' + cssCls + '">' + escapeHtml(session.status) + "</span>" +
206	      '<span class="time-ago">' + timeAgo(session.last_active) + "</span>" +
207	      '<span class="source-badge ' + session.source + '">' + session.source + "</span>";
208	
209	    row.addEventListener("click", function () {
210	      launchSession(session, row);
211	    });
212	
213	    return row;
214	  }
215	
216	  // Octocat SVG icon for git repo groups
217	  var OCTOCAT_SVG = '<svg class="octocat-icon" viewBox="0 0 16 16" width="14" height="14" fill="currentColor">' +
218	    '<path d="M8 0C3.58 0 0 3.58 0 8c0 3.54 2.29 6.53 5.47 7.59.4.07.55-.17.55-.38 0-.19-.01-.82-.01-1.49' +
219	    '-2.01.37-2.53-.49-2.69-.94-.09-.23-.48-.94-.82-1.13-.28-.15-.68-.52-.01-.53.63-.01 1.08.58 1.23.82' +
220	    '.72 1.21 1.87.87 2.33.66.07-.52.28-.87.51-1.07-1.78-.2-3.64-.89-3.64-3.95 0-.87.31-1.59.82-2.15' +
221	    '-.08-.2-.36-1.02.08-2.12 0 0 .67-.21 2.2.82.64-.18 1.32-.27 2-.27.68 0 1.36.09 2 .27 1.53-1.04 2.2-.82' +
222	    ' 2.2-.82.44 1.1.16 1.92.08 2.12.51.56.82 1.27.82 2.15 0 3.07-1.87 3.75-3.65 3.95.29.25.54.73.54 1.48' +
223	    ' 0 1.07-.01 1.93-.01 2.2 0 .21.15.46.55.38A8.013 8.013 0 0016 8c0-4.42-3.58-8-8-8z"/></svg>';
224	
225	  function buildGroupHeaderHtml(opts, isExpanded, sessionCount) {
226	    var chevron = '<span class="repo-chevron ' + (isExpanded ? "expanded" : "") + '" aria-hidden="true">\u25B6</span>';
227	    var icon = opts.icon || "";
228	    var name = '<span class="repo-name-display">' + escapeHtml(opts.displayName) + "</span>";
229	    var meta = '<span class="repo-meta-line">' + opts.metaText + "</span>";
230	    var btn = '<button class="btn-new-session" title="New Claude session in ' + escapeHtml(opts.cwd) + '" aria-label="New session in ' + escapeHtml(opts.displayName) + '">+</button>';
231	
232	    return (
233	      '<div class="repo-header-left">' + chevron + icon +
234	        '<div class="repo-header-info">' + name + meta + '</div>' +
235	      "</div>" +
236	      '<div class="repo-header-right">' + btn + timeAgo(opts.lastActive) + "</div>"
237	    );
238	  }
239	
240	  function renderGroup(opts, filteredSessions) {
241	    if (filteredSessions.length === 0) return null;
242	
243	    var groupKey = opts.groupKey;
244	    var isExpanded = expandedRepos.has(groupKey);
245	    var container = document.createElement("div");
246	    container.className = "repo-group";
247	
248	    var header = document.createElement("div");
249	    header.className = "repo-header";
250	    header.setAttribute("role", "button");
251	    header.setAttribute("aria-expanded", isExpanded ? "true" : "false");
252	    header.setAttribute("tabindex", "0");
253	    header.innerHTML = buildGroupHeaderHtml(opts, isExpanded, filteredSessions.length);
254	
255	    var sessionList = document.createElement("div");
256	    sessionList.className = "session-list" + (isExpanded ? "" : " collapsed");
257	
258	    // Render timeline if present, filtered by time slider
259	    if (opts.timeline && opts.timeline.length > 0) {
260	      var timelineEl = document.createElement("div");
261	      timelineEl.className = "repo-timeline";
262	      var cutoff = timeFilterDays === Infinity ? 0 : Date.now() - timeFilterDays * 24 * 60 * 60 * 1000;
263	      opts.timeline.forEach(function (phase) {
264	        if (cutoff > 0) {
265	          var phaseTime = parsePhaseDate(phase);
266	          if (phaseTime > 0 && phaseTime < cutoff) return;
267	        }
268	        var phaseEl = document.createElement("div");
269	        phaseEl.className = "timeline-phase";
270	        phaseEl.innerHTML =
271	          '<span class="timeline-period">' + escapeHtml(phase.period) + '</span>' +
272	          '<span class="timeline-desc">' + escapeHtml(phase.description) + '</span>';
273	        timelineEl.appendChild(phaseEl);
274	      });
275	      if (timelineEl.children.length > 0) {
276	        sessionList.appendChild(timelineEl);
277	      }
278	    }
279	
280	    var showingAll = filteredSessions.length <= INITIAL_VISIBLE;
281	
282	    function renderVisibleSessions() {
283	      var timeline = sessionList.querySelector(".repo-timeline");
284	      sessionList.innerHTML = "";
285	      if (timeline) sessionList.appendChild(timeline);
286	
287	      var toShow = showingAll ? filteredSessions : filteredSessions.slice(0, INITIAL_VISIBLE);
288	      toShow.forEach(function (session) {
289	        sessionList.appendChild(renderSessionRow(session));
290	      });
291	      if (!showingAll) {
292	        var moreBtn = document.createElement("div");
293	        moreBtn.className = "show-more-btn";
294	        moreBtn.textContent = "Show all " + filteredSessions.length + " sessions";
295	        moreBtn.addEventListener("click", function (e) {
296	          e.stopPropagation();
297	          showingAll = true;
298	          renderVisibleSessions();
299	          sessionList.style.maxHeight = sessionList.scrollHeight + "px";
300	        });
301	        sessionList.appendChild(moreBtn);
302	      }
303	    }
304	    renderVisibleSessions();
305	
306	    header.querySelector(".btn-new-session").addEventListener("click", function (e) {
307	      e.stopPropagation();
308	      openNewSession(opts.cwd);
309	    });
310	
311	    header.addEventListener("click", function () {
312	      if (expandedRepos.has(groupKey)) {
313	        expandedRepos.delete(groupKey);
314	        sessionList.classList.add("collapsed");
315	        header.querySelector(".repo-chevron").classList.remove("expanded");
316	        header.setAttribute("aria-expanded", "false");
317	      } else {
318	        expandedRepos.add(groupKey);
319	        sessionList.classList.remove("collapsed");
320	        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
321	        header.querySelector(".repo-chevron").classList.add("expanded");
322	        header.setAttribute("aria-expanded", "true");
323	      }
324	    });
325	
326	    if (isExpanded) {
327	      requestAnimationFrame(function () {
328	        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
329	      });
330	    }
331	
332	    container.appendChild(header);
333	    container.appendChild(sessionList);
334	    return container;
335	  }
336	
337	  function renderRepoGroup(group, filteredSessions) {
338	    var metaParts = [];
339	    if (group.git_branch) metaParts.push('<span class="meta-branch">' + escapeHtml(group.git_branch) + '</span>');
340	    if (group.git_dirty) metaParts.push('<span class="dirty">dirty</span>');
341	    if (group.unpushed_commits > 0) metaParts.push('<span class="unpushed">' + group.unpushed_commits + " unpushed</span>");
342	    if (!group.git_dirty && group.unpushed_commits === 0) metaParts.push('<span class="clean">clean</span>');
343	    metaParts.push('<span class="meta-count">' + filteredSessions.length + " session" + (filteredSessions.length !== 1 ? "s" : "") + '</span>');
344	
345	    return renderGroup({
346	      groupKey: group.repo_root,
347	      displayName: group.repo_name,
348	      icon: OCTOCAT_SVG,
349	      metaText: metaParts.join('<span class="meta-sep">\u00b7</span>'),
350	      cwd: group.repo_root,
351	      lastActive: group.last_active,
352	      timeline: group.timeline,
353	    }, filteredSessions);
354	  }
355	
356	  function renderNonRepoGroup(group, filteredSessions) {
357	    var displayName = group.cwd.split("/").filter(Boolean).pop() || group.cwd;
358	
359	    return renderGroup({
360	      groupKey: group.cwd,
361	      displayName: displayName,
362	      icon: "",
363	      metaText: '<span class="meta-count">' + filteredSessions.length + " session" + (filteredSessions.length !== 1 ? "s" : "") + '</span>',
364	      cwd: group.cwd,
365	      lastActive: group.last_active,
366	      timeline: group.timeline,
367	    }, filteredSessions);
368	  }
369	
370	  function render() {
371	    if (!dashboardData) return;
372	
373	    $loading.classList.add("hidden");
374	
375	    var hasRepos = (dashboardData.repo_groups || []).length > 0;
376	    var hasNonRepos = (dashboardData.non_repo_groups || []).length > 0;
377	
378	    if (!hasRepos && !hasNonRepos) {
379	      $emptyState.classList.remove("hidden");
380	      $repoGroups.classList.add("hidden");
381	      $nonRepoGroups.classList.add("hidden");
382	      $chronoView.classList.add("hidden");
383	      return;
384	    }
385	
386	    $emptyState.classList.add("hidden");
387	    $chronoView.classList.add("hidden");
388	    $repoGroups.classList.remove("hidden");
389	    $nonRepoGroups.classList.add("hidden");
390	
391	    // Combine repo and non-repo groups into one list sorted by last_active
392	    var allGroups = [];
393	    (dashboardData.repo_groups || []).forEach(function (g) {
394	      allGroups.push({ type: "repo", group: g, last_active: g.last_active });
395	    });
396	    (dashboardData.non_repo_groups || []).forEach(function (g) {
397	      allGroups.push({ type: "non-repo", group: g, last_active: g.last_active });
398	    });
399	    allGroups.sort(function (a, b) {
400	      return new Date(b.last_active) - new Date(a.last_active);
401	    });
402	
403	    // Auto-expand the first group on initial render
404	    if (expandedRepos.size === 0 && allGroups.length > 0) {
405	      var firstGroup = allGroups[0];
406	      var expandKey = firstGroup.type === "repo" ? firstGroup.group.repo_root : firstGroup.group.cwd;
407	      expandedRepos.add(expandKey);
408	    }
409	
410	    $repoGroups.innerHTML = "";
411	    allGroups.forEach(function (entry) {
412	      var filtered = filterGroupSessions(entry.group);
413	      var el = entry.type === "repo"
414	        ? renderRepoGroup(entry.group, filtered)
415	        : renderNonRepoGroup(entry.group, filtered);
416	      if (el) $repoGroups.appendChild(el);
417	    });
418	  }
419	
420	  // --- API ---
421	
422	  function fetchSessions() {
423	    return fetch("/api/sessions")
424	      .then(function (res) { return res.json(); })
425	      .then(function (data) {
426	        dashboardData = data;
427	        lastScannedTime = data.last_scanned;
428	        render();
429	        updateLastScan();
430	      })
431	      .catch(function (err) {
432	        console.error("Failed to fetch sessions:", err);
433	      });
434	  }
435	
436	  function refreshSessions() {
437	    var days = parseInt($scanDays.value, 10) || 7;
438	    $btnRefresh.classList.add("spinning");
439	    $btnRefresh.textContent = "Refreshing...";
440	    return fetch("/api/refresh?scan_days=" + days)
441	      .then(function (res) { return res.json(); })
442	      .then(function (data) {
443	        dashboardData = data;
444	        lastScannedTime = data.last_scanned;
445	        render();
446	        updateLastScan();
447	      })
448	      .catch(function (err) {
449	        console.error("Failed to refresh:", err);
450	      })
451	      .finally(function () {
452	        $btnRefresh.classList.remove("spinning");
453	        $btnRefresh.textContent = "Refresh";
454	      });
455	  }
456	
457	  function launchSession(session, rowEl) {
458	    rowEl.classList.add("launched");
459	    setTimeout(function () { rowEl.classList.remove("launched"); }, 500);
460	    var mode = localStorage.getItem("ak-view-mode") || "chat";
461	    if (mode === "chat" && window.AgentChat) {
462	      window.AgentChat.openChat(session);
463	    } else {
464	      openTerminal(session);
465	    }
466	  }
467	
468	  // --- Terminal Tabs ---
469	
470	  var terminals = {};       // tabId → tabData
471	  var activeTabId = null;
472	  var tabIdCounter = 0;
473	  var resizeListenerAttached = false;
474	
475	  var $terminalPanel = document.getElementById("terminal-panel");
476	  var $terminalContainer = document.getElementById("terminal-container");
477	  var $terminalTabs = document.getElementById("terminal-tabs");
478	  var $terminalClose = document.getElementById("terminal-close");
479	
480	  // Re-fit active terminal on any container size change (panel open/close,
481	  // tab switch, browser resize, etc.)
482	  var terminalResizeObserver = new ResizeObserver(function () {
483	    if (activeTabId && terminals[activeTabId]) {
484	      terminals[activeTabId].fitAddon.fit();
485	    }
486	  });
487	  terminalResizeObserver.observe($terminalContainer);
