748	    var all = allSessions();
749	    var scored = [];
750	    all.forEach(function (entry) {
751	      var label = sessionLabel(entry.session);
752	      var searchText = label + " " + entry.repoName + " " + (entry.session.status || "");
753	      var m = fuzzyMatch(searchText, query);
754	      if (m) {
755	        // Re-match just the label for highlighting
756	        var labelMatch = fuzzyMatch(label, query);
757	        scored.push({
758	          session: entry.session,
759	          repoName: entry.repoName,
760	          score: m.score,
761	          labelIndices: labelMatch ? labelMatch.indices : [],
762	        });
763	      }
764	    });
765	
766	    scored.sort(function (a, b) { return b.score - a.score; });
767	    searchMatches = scored.slice(0, 50);
768	
769	    if (searchMatches.length === 0) {
770	      $searchResults.innerHTML = '<div class="search-no-results">No matches</div>';
771	      return;
772	    }
