785	        '</div>' +
786	        '<span class="status-label ' + cssCls + '">' +
787	          escapeHtml(match.session.status) + '</span>' +
788	        '<span class="time-ago">' + timeAgo(match.session.last_active) + '</span>';
789	
790	      row.addEventListener("click", function () {
791	        closeSearch();
792	        launchFromSearch(match.session);
793	      });
794	      $searchResults.appendChild(row);
795	    });
