884	  function toggleFocusedGroup() {
885	    var groups = getAllGroupElements();
886	    if (focusedGroupIdx < 0 || focusedGroupIdx >= groups.length) return;
887	    var header = groups[focusedGroupIdx].querySelector(".repo-header");
888	    if (header) header.click();
