893	  document.addEventListener("keydown", function (e) {
894	    // Don't trigger if typing in an input or textarea
895	    if (e.target.tagName === "INPUT" || e.target.tagName === "TEXTAREA") return;
896	
897	    // Help overlay takes priority for close
898	    if (!$helpOverlay.classList.contains("hidden")) {
899	      if (e.key === "Escape" || e.key === "?") {
900	        e.preventDefault();
901	        closeHelp();
902	      }
903	      return;
904	    }
905	
906	    // Escape closes active terminal tab (returns focus to dashboard)
