910	      return;
911	    }
912	
913	    // When terminal is focused, only Escape works (handled above)
914	    if (activeTabId) return;
915	
916	    if (e.key === "/") {
917	      e.preventDefault();
918	      openSearch();
919	    } else if (e.key === "?") {
920	      e.preventDefault();
921	      openHelp();
922	    } else if (e.key === "r") {
923	      e.preventDefault();
924	      refreshSessions();
925	    } else if (e.key === "d") {
926	      e.preventDefault();
927	      cycleTheme();
928	    } else if (e.key === "j") {
929	      e.preventDefault();
930	      var groups = getAllGroupElements();
931	      if (groups.length > 0) {
932	        setGroupFocus(Math.min(focusedGroupIdx + 1, groups.length - 1));
933	      }
934	    } else if (e.key === "k") {
935	      e.preventDefault();
936	      if (focusedGroupIdx > 0) {
937	        setGroupFocus(focusedGroupIdx - 1);
938	      }
939	    } else if (e.key === "Enter" && focusedGroupIdx >= 0) {
940	      e.preventDefault();
941	      toggleFocusedGroup();
942	    }
943	  });
