.session-row {
  display: grid;
  grid-template-columns: 10px 1fr auto auto auto;
  align-items: center;
  gap: 14px;
  padding: 10px 16px;
  cursor: pointer;
  transition: all 150ms ease;
  line-height: 1.5;
  border-left: 3px solid transparent;
  border-bottom: 1px solid var(--border-light);
}

.session-row:last-child,
.session-row:has(+ .show-more-btn) {
  border-bottom: none;
}

.session-row:hover {
  background: var(--bg-hover);
  border-left-color: var(--accent);
}

.session-row.launched {
  animation: flash 400ms ease;
}

/* ===== Status Dot ===== */

.status-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
  transition: transform 150ms ease;
}

.status-dot.in-progress {
  width: 10px;
  height: 10px;
  background: var(--status-in-progress);
  animation: pulse-dot 2s ease-in-out infinite;
}

.status-dot.likely-in-progress {
  width: 10px;
  height: 10px;
  background: var(--status-likely-in-progress);
  animation: pulse-dot 2s ease-in-out infinite;
}

.status-dot.waiting-for-input {
  width: 10px;
  height: 10px;
  background: var(--status-waiting);
  animation: pulse-dot 2s ease-in-out infinite;
}

.status-dot.done {
  background: var(--status-done);
}

.status-dot.likely-done {
  background: var(--status-likely-done);
}

/* ===== Session Summary ===== */

.session-summary {
  font-size: var(--font-size-base);
  font-weight: 500;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  color: var(--text-secondary);
}

.session-fresh .session-summary {
  font-size: 15px;
  font-weight: 500;
  color: var(--text-primary);
}

/* ===== Status Label ===== */

.status-label {
  font-family: var(--font-mono);
  font-size: 8px;
  font-weight: 600;
  padding: 2px 8px;

