function updateActiveIndicators() {
  // Update all session rows to reflect current active/streaming state
  var rows = $repoGroups.querySelectorAll(".session-row[data-session-id]");
  if (!window.AgentChat) return;
  var activeIds = window.AgentChat.getActiveSessionIds();
  var activeSessions = window.AgentChat.getActiveSessions();

  rows.forEach(function (row) {
    var sid = row.getAttribute("data-session-id");
    var isActive = activeIds.has(sid);
    var isStreaming = activeSessions[sid] && activeSessions[sid].streaming;

    row.classList.toggle("session-active", isActive);
    row.classList.toggle("session-streaming", isStreaming);

    // Update the status dot streaming class
    var dot = row.querySelector(".status-dot");
    if (dot) dot.classList.toggle("streaming", isStreaming);

    // Add/remove active indicator
    var indicator = row.querySelector(".active-indicator");
    if (isActive && !indicator) {
      var newIndicator = document.createElement("span");
      newIndicator.className = "active-indicator";
      newIndicator.title = "Open in chat panel";
      newIndicator.innerHTML = "&#9679;";
      row.insertBefore(newIndicator, row.querySelector(".session-summary"));
    } else if (!isActive && indicator) {
      indicator.remove();
    }
  });
}

